#include<bits/stdc++.h>
using namespace std;
int x[10]={6,2,5,5,4,5,6,3,7,6},n;
int intis(int m){
	int sum=0;
	if(!m)return x[0]; 
	while(m){
		sum+=x[m%10];
		m/=10;
	}
	return sum;
}
int f(int p){
	int ans=0;
	for(int i=0;i<=999;i++){
		for(int j=0;j<=999;j++){
			if(intis(i)+intis(j)+4+intis(i+j)==p){
				ans+=1;
			}
		}
	}return ans;
}
int main(void){
	cin>>n;
	cout<<f(n);
    return false;
}
